from __future__ import annotations


def flatten_paths(value):
    out = {}
    stack = [('', value)]
    while stack:
        prefix, item = stack.pop()
        if isinstance(item, dict):
            for key, child in reversed(list(item.items())):
                stack.append((f'{prefix}.{key}' if prefix else str(key), child))
        else:
            out[prefix] = item
    return out

